def solve(prices: list[int], strategy: list[int], k: int) -> int:
    n = len(prices)
    prefix_prices = [0] * (n + 1)
    for i in range(n):
        prefix_prices[i + 1] = prefix_prices[i] + prices[i]

    prefix_original = [0] * (n + 1)
    for i in range(n):
        prefix_original[i + 1] = prefix_original[i] + strategy[i] * prices[i]

    original_profit = prefix_original[n]
    max_delta = -float('inf')
    half_k = k // 2

    for i in range(n - k + 1):
        sum_second_half = prefix_prices[i + k] - prefix_prices[i + half_k]
        sum_original_window = prefix_original[i + k] - prefix_original[i]
        delta = sum_second_half - sum_original_window
        if delta > max_delta:
            max_delta = delta

    return original_profit + max(0, max_delta)
